  ('social-worker-moex-01964', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關Fred Fiedler權變模式理論影響領導者效能情境因素三變數敘述，以下何者錯誤？', '["情境變數高且情境極度有利時採取「生產任務取向」", "情境變數弱而且不利情境下採取「生產任務取向」", "變數強弱有別，但情境屬於中等有利時，採「員工關係取向」", "情境變數弱而且不利情境下採取「員工關係取向」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01965', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關「領導（leadership）」與「管理（management）」的區別，何者錯誤？', '["領導主要指規劃、組織、協調和控制他人行為，管理是關係到誘發、因應和協助適應變遷", "管理促進穩定協助作業進行重視內部平衡，領導則有促進適應或變遷回應外部意味", "控制與解決問題在於管理，領導在於激勵士氣", "依據法定權力，維持組織達成目標是管理，引領他人尋求並確定目標是領導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
