  ('social-worker-moex-01967', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某心智障礙住宿機構爆發員生遭到工作人員性侵害事件，引起社會軒然大波與媒體關注。下列機構主事 者第一時間處理應該注意事項的敘述，何者比較不適當？', '["責由機構具能力者調查與善後", "讓媒體感受機構面對事件處理決心", "邀請政府部門立即進駐調查", "配合適當時機提供不具隱私性的資訊給予媒體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
