  ('social-worker-moex-01970', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務機構經常面對危機發生與處理，有關危機的敘述，何者正確？', '["對社會服務機構而言，危機發生未必全然不好", "機構不同於個人，管理者其實無法事先發覺危機，僅能發生後立即處置", "危機處理率先關注的是事件本身檢討才是最重要的", "必須考量機構於社會觀感與評價，重於真相公布"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "f80e8558d678", "answer_pdf_sha1": "ce4f756709e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
